mapper.select:
SELECT proc_code, proc_name, note, get_mes_sub_code_name(proc_class_code) procClassName, fac_class_code, proc_class_code FROM proc
AND PROC_CLASS_CODE= #{procClassCode}
AND proc_name LIKE '%'||#{procName}||'%'

mapper.update:
         UPDATE proc_flow
		 SET proc_num=#{procNum},
 	    	 proc_code=#{procCode},
 	    	 proc_name=#{procName},
   			 note=#{note}
		WHERE proc_flow_code=#{procFlowCode}
